static int emit_report_types(const GlobalOpts& opts) {
    const QJsonArray types{
        QJsonObject{{"name", "heading"}, {"accepts_content", true}, {"content_format", "plain"}},
        QJsonObject{{"name", "text"}, {"accepts_content", true}, {"content_format", "markdown"}},
        QJsonObject{{"name", "list"}, {"accepts_content", true}, {"content_format", "markdown, one item per line"}},
        QJsonObject{{"name", "quote"}, {"accepts_content", true}, {"content_format", "markdown"}},
        QJsonObject{{"name", "callout"}, {"accepts_content", true}, {"config_keys", QJsonArray{"style", "heading"}}},
        QJsonObject{{"name", "code"}, {"accepts_content", true}, {"config_keys", QJsonArray{"language"}}},
        QJsonObject{{"name", "divider"}, {"accepts_content", false}},
        QJsonObject{{"name", "page_break"}, {"accepts_content", false}},
        QJsonObject{{"name", "toc"}, {"accepts_content", false}},
        QJsonObject{{"name", "table"}, {"accepts_content", false}, {"config_keys", QJsonArray{"csv"}}},
        QJsonObject{{"name", "chart"}, {"accepts_content", false}, {"config_keys", QJsonArray{"chart_type", "title", "data", "labels", "width"}}},
        QJsonObject{{"name", "sparkline"}, {"accepts_content", false}, {"config_keys", QJsonArray{"title", "data", "current", "change_pct"}}},
        QJsonObject{{"name", "stats_block"}, {"accepts_content", false}, {"config_keys", QJsonArray{"title", "data"}}},
        QJsonObject{{"name", "market_data"}, {"accepts_content", false}, {"config_keys", QJsonArray{"symbol"}}},
        QJsonObject{{"name", "image"}, {"accepts_content", false}, {"config_keys", QJsonArray{"path", "width", "caption", "align"}}}
    };
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(QJsonObject{{"types", types}}).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("%-14s %-8s %s\n", "type", "content", "config");
    for (const auto& v : types) {
        const QJsonObject t = v.toObject();
        QStringList keys;
        for (const auto& k : t.value("config_keys").toArray())
            keys << k.toString();
        std::printf("%-14s %-8s %s\n",
                    qUtf8Printable(t.value("name").toString()),
                    t.value("accepts_content").toBool() ? "yes" : "no",
                    qUtf8Printable(keys.join(',')));
    }
    return 0;
}

static int emit_report_templates(const GlobalOpts& opts) {
    const QStringList names = report_template_names();
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(QJsonObject{{"templates", QJsonArray::fromStringList(names)}})
                                .toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    for (const auto& name : names)
        std::printf("%s\n", qUtf8Printable(name));
    return 0;
}

static int report_command(const GlobalOpts& opts, QStringList args) {
    int code = 0;
    if (!init_headless_for_cli(opts, code))
        return code;
    auto& svc = services::ReportBuilderService::instance();
    const QString sub = args.isEmpty() ? QStringLiteral("state") : args.takeFirst().trimmed().toLower();
    if (sub != "load")
        report_restore_cli_state(svc);

    if (sub == "state" || sub == "show" || sub == "get")
        return emit_report_state(opts, svc);

    if (sub == "types")
        return emit_report_types(opts);

    if (sub == "templates")
        return emit_report_templates(opts);

    if (sub == "add") {
        QString content;
        QString content_file;
        QString config_raw;
        QString at_raw;
        if (!take_string_option(args, QStringLiteral("--content"), content) ||
            !take_string_option(args, QStringLiteral("--content-file"), content_file) ||
            !take_string_option(args, QStringLiteral("--config"), config_raw) ||
            !take_string_option(args, QStringLiteral("--at"), at_raw))
            return 2;
        if (!require_yes(args, "usage: report add <type> [--content TEXT | --content-file PATH] [--config JSON] [--at N] --yes"))
            return 2;
        if (args.size() != 1 || (!content.isEmpty() && !content_file.isEmpty())) {
            std::fprintf(stderr, "usage: report add <type> [--content TEXT | --content-file PATH] [--config JSON] [--at N] --yes\n");
            return 2;
        }
        const QString type = args.first().trimmed().toLower();
        if (!report_valid_component_type(type)) {
            std::fprintf(stderr, "unknown report component type: %s\n", qUtf8Printable(type));
            return 2;
        }
        if (!content_file.isEmpty()) {
            QString err;
            if (!read_text_file(content_file, content, err)) {
                std::fprintf(stderr, "%s\n", qUtf8Printable(err));
                return 2;
            }
        }
        QJsonObject config_json;
        if (!config_raw.isEmpty()) {
            QString err;
            if (!parse_json_object_text(config_raw, config_json, err)) {
                std::fprintf(stderr, "%s\n", qUtf8Printable(err));
                return 2;
            }
        }
        bool ok_at = true;
        int at = -1;
        if (!at_raw.isEmpty()) {
            at = at_raw.toInt(&ok_at);
            if (!ok_at) {
                std::fprintf(stderr, "--at requires an integer\n");
                return 2;
            }
        }
        report::ReportComponent comp;
        comp.type = type;
        comp.content = content;
        comp.config = report_config_from_json(config_json);
        const int id = svc.add_component(comp, at);
        QString persist_err;
        if (!report_persist_cli_state(svc, persist_err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(persist_err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report component added"),
                                                      QJsonObject{{"id", id}, {"type", type}, {"index", svc.index_of(id)}}));
    }

    if (sub == "bulk") {
        if (!require_yes(args, "usage: report bulk <components-json|@file|-> --yes"))
            return 2;
        if (args.isEmpty()) {
            std::fprintf(stderr, "usage: report bulk <components-json|@file|-> --yes\n");
            return 2;
        }
        QJsonValue raw;
        QString err;
        if (!parse_json_value_text(args.join(' '), raw, err)) {
            std::fprintf(stderr, "%s\n", qUtf8Printable(err));
            return 2;
        }
        QJsonArray arr = raw.isArray() ? raw.toArray() : raw.toObject().value("components").toArray();
        if (arr.isEmpty()) {
            std::fprintf(stderr, "bulk input must be a JSON array or object with non-empty components array\n");
            return 2;
        }
        for (int i = 0; i < arr.size(); ++i) {
            const QJsonObject c = arr.at(i).toObject();
            const QString type = c.value("type").toString().trimmed().toLower();
            if (!report_valid_component_type(type)) {
                std::fprintf(stderr, "components[%d]: unknown type '%s'\n", i, qUtf8Printable(type));
                return 2;
            }
        }
        QJsonArray ids;
        svc.begin_macro(QStringLiteral("CLI bulk add components"));
        for (const auto& v : arr) {
            const QJsonObject c = v.toObject();
            report::ReportComponent comp;
            comp.type = c.value("type").toString().trimmed().toLower();
            comp.content = c.value("content").toString();
            comp.config = report_config_from_json(c.value("config").toObject());
            ids.append(svc.add_component(comp, -1));
        }
        svc.end_macro();
        QString bulk_persist_err;
        if (!report_persist_cli_state(svc, bulk_persist_err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(bulk_persist_err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report components added"),
                                                      QJsonObject{{"ids", ids}, {"count", ids.size()}}));
    }

    if (sub == "update" || sub == "edit") {
        QString content;
        QString content_file;
        QString config_raw;
        if (!take_string_option(args, QStringLiteral("--content"), content) ||
            !take_string_option(args, QStringLiteral("--content-file"), content_file) ||
            !take_string_option(args, QStringLiteral("--config"), config_raw))
            return 2;
        if (!require_yes(args, "usage: report update <component-id> [--content TEXT | --content-file PATH] [--config JSON] --yes"))
            return 2;
        bool ok_id = false;
        const int id = args.isEmpty() ? 0 : args.first().toInt(&ok_id);
        if (args.size() != 1 || !ok_id || id <= 0 || (!content.isEmpty() && !content_file.isEmpty())) {
            std::fprintf(stderr, "usage: report update <component-id> [--content TEXT | --content-file PATH] [--config JSON] --yes\n");
            return 2;
        }
        if (!content_file.isEmpty()) {
            QString err;
            if (!read_text_file(content_file, content, err)) {
                std::fprintf(stderr, "%s\n", qUtf8Printable(err));
                return 2;
            }
        }
        QJsonObject config_json;
        if (!config_raw.isEmpty()) {
            QString err;
            if (!parse_json_object_text(config_raw, config_json, err)) {
                std::fprintf(stderr, "%s\n", qUtf8Printable(err));
                return 2;
            }
        }
        const QString* content_ptr = (!content.isEmpty() || !content_file.isEmpty()) ? &content : nullptr;
        if (!svc.patch_component(id, content_ptr, report_config_from_json(config_json))) {
            std::fprintf(stderr, "report component not found: %d\n", id);
            return 5;
        }
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report component updated"),
                                                      QJsonObject{{"id", id}}));
    }

    if (sub == "remove" || sub == "delete" || sub == "rm") {
        if (!require_yes(args, "usage: report remove <component-id> --yes"))
            return 2;
        bool ok_id = false;
        const int id = args.size() == 1 ? args.first().toInt(&ok_id) : 0;
        if (!ok_id || id <= 0) {
            std::fprintf(stderr, "usage: report remove <component-id> --yes\n");
            return 2;
        }
        if (!svc.remove_component(id)) {
            std::fprintf(stderr, "report component not found: %d\n", id);
            return 5;
        }
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report component removed"), QJsonObject{{"id", id}}));
    }

    if (sub == "move") {
        if (!require_yes(args, "usage: report move <component-id> <to-index> --yes"))
            return 2;
        bool ok_id = false;
        bool ok_idx = false;
        const int id = args.size() >= 1 ? args.at(0).toInt(&ok_id) : 0;
        const int index = args.size() >= 2 ? args.at(1).toInt(&ok_idx) : -1;
        if (args.size() != 2 || !ok_id || !ok_idx || id <= 0) {
            std::fprintf(stderr, "usage: report move <component-id> <to-index> --yes\n");
            return 2;
        }
        if (!svc.move_component(id, index)) {
            std::fprintf(stderr, "report component not found: %d\n", id);
            return 5;
        }
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report component moved"),
                                                      QJsonObject{{"id", id}, {"index", svc.index_of(id)}}));
    }

    if (sub == "clear") {
        if (!require_yes(args, "usage: report clear --yes"))
            return 2;
        if (!args.isEmpty()) {
            std::fprintf(stderr, "usage: report clear --yes\n");
            return 2;
        }
        svc.clear_document();
        QFile::remove(svc.autosave_path());
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report cleared")));
    }

    if (sub == "metadata" || sub == "meta") {
        if (args.isEmpty()) {
            if (opts.json)
                std::printf("%s\n", QJsonDocument(report_metadata_to_json(svc.metadata())).toJson(QJsonDocument::Compact).constData());
            else
                std::printf("%s\n", QJsonDocument(report_metadata_to_json(svc.metadata())).toJson(QJsonDocument::Indented).constData());
            return 0;
        }
        if (!require_yes(args, "usage: report metadata key=value ... --yes"))
            return 2;
        report::ReportMetadata m = svc.metadata();
        for (const QString& tok : args) {
            const int eq = tok.indexOf('=');
            if (eq <= 0) {
                std::fprintf(stderr, "expected key=value: %s\n", qUtf8Printable(tok));
                return 2;
            }
            const QString key = tok.left(eq).trimmed().toLower();
            const QString value = tok.mid(eq + 1);
            if (key == "title") m.title = value;
            else if (key == "author") m.author = value;
            else if (key == "company") m.company = value;
            else if (key == "date") m.date = value;
            else if (key == "header_left") m.header_left = value;
            else if (key == "header_center") m.header_center = value;
            else if (key == "header_right") m.header_right = value;
            else if (key == "footer_left") m.footer_left = value;
            else if (key == "footer_center") m.footer_center = value;
            else if (key == "footer_right") m.footer_right = value;
            else if (key == "show_page_numbers") {
                const QString v = value.toLower();
                m.show_page_numbers = (v == "true" || v == "1" || v == "yes" || v == "on");
            } else {
                std::fprintf(stderr, "unknown metadata field: %s\n", qUtf8Printable(key));
                return 2;
            }
        }
        svc.set_metadata(m);
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report metadata updated"),
                                                      report_metadata_to_json(svc.metadata())));
    }

    if (sub == "theme") {
        if (!require_yes(args, "usage: report theme <name> --yes"))
            return 2;
        const QString name = args.join(' ').trimmed();
        if (name.isEmpty() || !report::themes::all_names().contains(name)) {
            std::fprintf(stderr, "usage: report theme <name> --yes\nvalid: %s\n",
                         qUtf8Printable(report::themes::all_names().join(QStringLiteral(", "))));
            return 2;
        }
        svc.set_theme(report::themes::by_name(name));
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report theme updated"), QJsonObject{{"theme", name}}));
    }

    if (sub == "template") {
        if (!require_yes(args, "usage: report template <name...> --yes"))
            return 2;
        const QString name = args.join(' ').trimmed();
        if (name.isEmpty()) {
            std::fprintf(stderr, "usage: report template <name...> --yes\n");
            return 2;
        }
        svc.apply_template(name);
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report template applied"), QJsonObject{{"template", name}}));
    }

    if (sub == "save") {
        const bool managed = take_bool_flag(args, QStringLiteral("--managed"));
        if (!require_yes(args, "usage: report save <path> [--managed] --yes"))
            return 2;
        if (args.size() != 1) {
            std::fprintf(stderr, "usage: report save <path> [--managed] --yes\n");
            return 2;
        }
        const QString path = args.first();
        auto r = svc.save_to(path);
        if (r.is_err()) {
            std::fprintf(stderr, "failed to save report: %s\n", r.error().c_str());
            return 5;
        }
        QJsonObject data{{"path", path}};
        if (managed) {
            const QString file_id = services::FileManagerService::instance().import_file(path, QStringLiteral("report_builder"));
            if (file_id.isEmpty()) {
                std::fprintf(stderr, "report saved but failed to import into File Manager\n");
                return 5;
            }
            data["file_id"] = file_id;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report saved"), data));
    }

    if (sub == "load") {
        if (!require_yes(args, "usage: report load <path> --yes"))
            return 2;
        if (args.size() != 1) {
            std::fprintf(stderr, "usage: report load <path> --yes\n");
            return 2;
        }
        auto r = svc.load_from(args.first());
        if (r.is_err()) {
            std::fprintf(stderr, "failed to load report: %s\n", r.error().c_str());
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Report loaded"), QJsonObject{{"path", args.first()}}));
    }

    if (sub == "undo" || sub == "redo") {
        if (!require_yes(args, sub == "undo" ? "usage: report undo --yes" : "usage: report redo --yes"))
            return 2;
        if (!args.isEmpty()) {
            std::fprintf(stderr, "usage: report %s --yes\n", qUtf8Printable(sub));
            return 2;
        }
        QUndoStack* stack = svc.undo_stack();
        if (sub == "undo") {
            if (!stack->canUndo()) {
                std::fprintf(stderr, "nothing to undo\n");
                return 5;
            }
            stack->undo();
        } else {
            if (!stack->canRedo()) {
                std::fprintf(stderr, "nothing to redo\n");
                return 5;
            }
            stack->redo();
        }
        QString err;
        if (!report_persist_cli_state(svc, err)) {
            std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(err));
            return 5;
        }
        return emit_mutation_body(opts, mutation_body(sub == "undo" ? QStringLiteral("Report undo applied")
                                                                    : QStringLiteral("Report redo applied")));
    }

    if (sub == "tool") {
        if (args.isEmpty()) {
            std::fprintf(stderr, "usage: report tool <mcp-tool> key=value ...\n");
            return 2;
        }
        const QString tool = args.takeFirst();
        QJsonObject a;
        QString err;
        if (!parse_tool_args(args, a, err)) {
            std::fprintf(stderr, "%s\n", qUtf8Printable(err));
            return 2;
        }
        QJsonObject body;
        const int rc = call_headless_tool_json(opts, tool, a, body);
        if (rc != 0)
            return rc;
        if (tool.startsWith(QStringLiteral("report_")) && tool != QStringLiteral("report_get_state") &&
            tool != QStringLiteral("report_list_component_types") && tool != QStringLiteral("report_list_templates") &&
            tool != QStringLiteral("report_export_pdf")) {
            QString persist_err;
            if (!report_persist_cli_state(svc, persist_err)) {
                std::fprintf(stderr, "failed to persist report: %s\n", qUtf8Printable(persist_err));
                return 5;
            }
        }
        if (opts.json)
            std::printf("%s\n", QJsonDocument(body).toJson(QJsonDocument::Compact).constData());
        else
            std::printf("%s\n", QJsonDocument(body).toJson(QJsonDocument::Indented).constData());
        return 0;
    }

    std::fprintf(stderr, "usage: report state|types|templates|add|bulk|update|remove|move|clear|metadata|theme|template|save|load|undo|redo|tool\n");
    return 2;
}

struct NotifyFieldDef {
    QString key;
    QString label;
    bool secret{false};
};

struct NotifyProviderDef {
    QString id;
    QString name;
    QVector<NotifyFieldDef> fields;
};

static const QVector<NotifyProviderDef>& notify_provider_defs() {
    static const QVector<NotifyProviderDef> defs = {
        {"telegram", "Telegram", {{"bot_token", "Bot Token", true}, {"chat_id", "Chat ID", false}}},
        {"discord", "Discord", {{"webhook_url", "Webhook URL", true}}},
        {"slack", "Slack", {{"webhook_url", "Webhook URL", true}, {"channel", "Channel", false}}},
        {"email", "Email", {{"smtp_host", "SMTP Host", false}, {"smtp_port", "Port", false},
                            {"smtp_user", "Username", false}, {"smtp_pass", "Password", true},
                            {"to_addr", "To Address", false}, {"from_addr", "From Address", false}}},
        {"whatsapp", "WhatsApp", {{"account_sid", "Account SID", false}, {"auth_token", "Auth Token", true},
                                  {"from_number", "From Number", false}, {"to_number", "To Number", false}}},
        {"pushover", "Pushover", {{"api_token", "API Token", true}, {"user_key", "User Key", true}}},
        {"ntfy", "ntfy", {{"server_url", "Server URL", false}, {"topic", "Topic", false}, {"token", "Auth Token", true}}},
        {"pushbullet", "Pushbullet", {{"api_key", "API Key", true}, {"channel_tag", "Channel Tag", false}}},
        {"gotify", "Gotify", {{"server_url", "Server URL", false}, {"app_token", "App Token", true}}},
        {"mattermost", "Mattermost", {{"webhook_url", "Webhook URL", true}, {"channel", "Channel", false},
                                      {"username", "Username", false}}},
        {"teams", "MS Teams", {{"webhook_url", "Webhook URL", true}}},
        {"webhook", "Webhook", {{"url", "URL", true}, {"method", "Method", false}}},
        {"pagerduty", "PagerDuty", {{"routing_key", "Routing Key", true}}},
        {"opsgenie", "Opsgenie", {{"api_key", "API Key", true}}},
        {"sms", "SMS (Twilio)", {{"account_sid", "Account SID", false}, {"auth_token", "Auth Token", true},
                                 {"from_number", "From Number", false}, {"to_number", "To Number", false}}},
    };
    return defs;
}

static std::optional<NotifyProviderDef> notify_provider_def(const QString& id) {
    const QString wanted = id.trimmed().toLower();
    for (const auto& def : notify_provider_defs()) {
        if (def.id == wanted)
            return def;
    }
    return std::nullopt;
}

static bool notify_field_exists(const NotifyProviderDef& def, const QString& key) {
    if (key == "enabled")
        return true;
    for (const auto& f : def.fields) {
        if (f.key == key)
            return true;
    }
    return false;
}

static QString notify_mask_value(const QString& value, bool secret) {
    if (value.isEmpty())
        return {};
    if (!secret)
        return value;
    if (value.size() <= 6)
        return QStringLiteral("******");
    return value.left(2) + QStringLiteral("...") + value.right(2);
}

static bool parse_cli_bool(const QString& raw) {
    const QString v = raw.trimmed().toLower();
    return v == "1" || v == "true" || v == "yes" || v == "on" || v == "enabled";
}

static notifications::NotifLevel parse_notify_level(QString raw, bool& ok) {
    raw = raw.trimmed().toLower();
    ok = true;
    if (raw.isEmpty() || raw == "info") return notifications::NotifLevel::Info;
    if (raw == "warning" || raw == "warn") return notifications::NotifLevel::Warning;
    if (raw == "alert") return notifications::NotifLevel::Alert;
    if (raw == "critical" || raw == "crit") return notifications::NotifLevel::Critical;
    ok = false;
    return notifications::NotifLevel::Info;
}

static QString notify_level_text(notifications::NotifLevel level) {
    switch (level) {
        case notifications::NotifLevel::Warning: return QStringLiteral("warning");
        case notifications::NotifLevel::Alert: return QStringLiteral("alert");
        case notifications::NotifLevel::Critical: return QStringLiteral("critical");
        case notifications::NotifLevel::Info:
        default: return QStringLiteral("info");
    }
}

static QJsonObject notify_provider_to_json(const NotifyProviderDef& def,
                                           notifications::INotificationProvider* provider) {
    auto& repo = SettingsRepository::instance();
    const QString cat = QStringLiteral("notif_") + def.id;
    QJsonObject fields;
    for (const auto& f : def.fields) {
        const auto value_res = repo.get(cat + QStringLiteral(".") + f.key);
        const QString value = value_res.is_ok() ? value_res.value() : QString{};
        fields[f.key] = QJsonObject{{"set", !value.isEmpty()},
                                    {"secret", f.secret},
                                    {"value", notify_mask_value(value, f.secret)}};
    }
    return QJsonObject{{"id", def.id},
                       {"name", def.name},
                       {"enabled", provider ? provider->is_enabled() : false},
                       {"configured", provider ? provider->is_configured() : false},
                       {"fields", fields}};
}

static QJsonObject notify_triggers_json() {
    auto& repo = SettingsRepository::instance();
    auto b = [&](const QString& key, bool def) {
        const QString fallback = def ? QStringLiteral("1") : QStringLiteral("0");
        const auto value_res = repo.get(key, fallback);
        const QString v = value_res.is_ok() ? value_res.value() : fallback;
        return v == "1";
    };
    return QJsonObject{{"inapp", b(QStringLiteral("notifications.inapp"), true)},
                       {"price_alerts", b(QStringLiteral("notifications.price_alerts"), true)},
                       {"news_alerts", b(QStringLiteral("notifications.news_alerts"), false)},
                       {"order_fills", b(QStringLiteral("notifications.order_fills"), true)},
                       {"news_breaking", b(QStringLiteral("notifications.news_breaking"), true)},
                       {"news_monitors", b(QStringLiteral("notifications.news_monitors"), true)},
                       {"news_deviations", b(QStringLiteral("notifications.news_deviations"), true)},
                       {"news_flash", b(QStringLiteral("notifications.news_flash"), true)}};
}

static int emit_notify_providers(const GlobalOpts& opts, notifications::NotificationService& svc) {
    QJsonArray arr;
    for (const auto& def : notify_provider_defs())
        arr.append(notify_provider_to_json(def, svc.provider(def.id)));
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(QJsonObject{{"providers", arr}}).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("%-14s %-18s %-8s %-10s %s\n", "id", "name", "enabled", "configured", "fields");
    for (const auto& v : arr) {
        const QJsonObject p = v.toObject();
        QStringList fields;
        const auto def = notify_provider_def(p.value("id").toString());
        if (def) {
            for (const auto& f : def->fields)
                fields << f.key;
        }
        std::printf("%-14s %-18s %-8s %-10s %s\n",
                    qUtf8Printable(p.value("id").toString()),
                    qUtf8Printable(p.value("name").toString()),
                    p.value("enabled").toBool() ? "yes" : "no",
                    p.value("configured").toBool() ? "yes" : "no",
                    qUtf8Printable(fields.join(',')));
    }
    return 0;
}

static int emit_notify_config(const GlobalOpts& opts, const NotifyProviderDef& def,
                              notifications::NotificationService& svc) {
    const QJsonObject obj = notify_provider_to_json(def, svc.provider(def.id));
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(obj).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("id          %s\n", qUtf8Printable(def.id));
    std::printf("name        %s\n", qUtf8Printable(def.name));
    std::printf("enabled     %s\n", obj.value("enabled").toBool() ? "yes" : "no");
    std::printf("configured  %s\n", obj.value("configured").toBool() ? "yes" : "no");
    const QJsonObject fields = obj.value("fields").toObject();
    for (const auto& f : def.fields) {
        const QJsonObject entry = fields.value(f.key).toObject();
        QString value = entry.value("value").toString();
        if (value.isEmpty())
            value = QStringLiteral("<not set>");
        std::printf("%-12s %s\n", qUtf8Printable(f.key), qUtf8Printable(value));
    }
    return 0;
}

static int emit_notify_status(const GlobalOpts& opts, notifications::NotificationService& svc) {
    int enabled = 0;
    int configured = 0;
    QJsonArray providers;
    for (const auto& def : notify_provider_defs()) {
        auto* p = svc.provider(def.id);
        if (p && p->is_enabled()) ++enabled;
        if (p && p->is_configured()) ++configured;
        providers.append(notify_provider_to_json(def, p));
    }
    const QJsonObject out{{"provider_count", notify_provider_defs().size()},
                          {"enabled_count", enabled},
                          {"configured_count", configured},
                          {"unread_count", svc.unread_count()},
                          {"triggers", notify_triggers_json()},
                          {"providers", providers}};
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(out).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("providers    %lld\n", static_cast<long long>(notify_provider_defs().size()));
    std::printf("enabled      %d\n", enabled);
    std::printf("configured   %d\n", configured);
    std::printf("unread       %d\n", svc.unread_count());
    const QJsonObject triggers = out.value("triggers").toObject();
    std::printf("triggers     inapp=%s price=%s news=%s orders=%s\n",
                triggers.value("inapp").toBool() ? "on" : "off",
                triggers.value("price_alerts").toBool() ? "on" : "off",
                triggers.value("news_alerts").toBool() ? "on" : "off",
                triggers.value("order_fills").toBool() ? "on" : "off");
    return 0;
}

static int emit_notify_triggers(const GlobalOpts& opts) {
    const QJsonObject triggers = notify_triggers_json();
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(triggers).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    for (const QString& key : triggers.keys())
        std::printf("%-18s %s\n", qUtf8Printable(key), triggers.value(key).toBool() ? "on" : "off");
    return 0;
}

static bool notify_wait_send(notifications::INotificationProvider* provider,
                             const notifications::NotificationRequest& req,
                             int timeout_ms,
                             bool& ok,
                             QString& error) {
    if (!provider) {
        ok = false;
        error = QStringLiteral("provider not found");
        return true;
    }
    QEventLoop loop;
    QTimer timer;
    timer.setSingleShot(true);
    bool finished = false;
    QObject::connect(&timer, &QTimer::timeout, &loop, [&]() {
        if (!finished) {
            finished = true;
            ok = false;
            error = QStringLiteral("timed out");
            loop.quit();
        }
    });
    provider->send(req, [&](bool send_ok, QString send_error) {
        if (finished)
            return;
        finished = true;
        ok = send_ok;
        error = std::move(send_error);
        loop.quit();
    });
    if (finished)
        return true;
    timer.start(timeout_ms);
    loop.exec();
    return finished;
}

static int notify_command(const GlobalOpts& opts, QStringList args) {
    int code = 0;
    if (!init_headless_for_cli(opts, code))
        return code;
    auto& svc = notifications::NotificationService::instance();
    auto& repo = SettingsRepository::instance();
    const QString sub = args.isEmpty() ? QStringLiteral("status") : args.takeFirst().trimmed().toLower();

    if (sub == "providers" || sub == "list" || sub == "ls")
        return emit_notify_providers(opts, svc);

    if (sub == "status")
        return emit_notify_status(opts, svc);

    if (sub == "config" || sub == "show") {
        if (args.size() != 1) {
            std::fprintf(stderr, "usage: notify config <provider>\n");
            return 2;
        }
        const auto def = notify_provider_def(args.first());
        if (!def) {
            std::fprintf(stderr, "unknown notification provider: %s\n", qUtf8Printable(args.first()));
            return 2;
        }
        return emit_notify_config(opts, *def, svc);
    }

    if (sub == "set") {
        if (!require_yes(args, "usage: notify set <provider> key=value ... --yes"))
            return 2;
        if (args.size() < 2) {
            std::fprintf(stderr, "usage: notify set <provider> key=value ... --yes\n");
            return 2;
        }
        const auto def = notify_provider_def(args.takeFirst());
        if (!def) {
            std::fprintf(stderr, "unknown notification provider\n");
            return 2;
        }
        const QString cat = QStringLiteral("notif_") + def->id;
        for (const QString& tok : args) {
            const int eq = tok.indexOf('=');
            if (eq <= 0) {
                std::fprintf(stderr, "expected key=value: %s\n", qUtf8Printable(tok));
                return 2;
            }
            const QString key = tok.left(eq).trimmed();
            const QString value = tok.mid(eq + 1);
            if (!notify_field_exists(*def, key)) {
                std::fprintf(stderr, "unknown field for %s: %s\n", qUtf8Printable(def->id), qUtf8Printable(key));
                return 2;
            }
            const QString setting_key = key == "enabled" ? cat + QStringLiteral(".enabled") : cat + QStringLiteral(".") + key;
            auto r = repo.set(setting_key, key == "enabled" ? (parse_cli_bool(value) ? QStringLiteral("1") : QStringLiteral("0")) : value, cat);
            if (r.is_err()) {
                std::fprintf(stderr, "failed to save notification config: %s\n", r.error().c_str());
                return 5;
            }
        }
        svc.reload_all_configs();
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Notification provider updated"),
                                                      QJsonObject{{"provider", def->id}}));
    }

    if (sub == "enable" || sub == "disable") {
        if (!require_yes(args, sub == "enable" ? "usage: notify enable <provider> --yes"
                                               : "usage: notify disable <provider> --yes"))
            return 2;
        if (args.size() != 1) {
            std::fprintf(stderr, "usage: notify %s <provider> --yes\n", qUtf8Printable(sub));
            return 2;
        }
        const auto def = notify_provider_def(args.first());
        if (!def) {
            std::fprintf(stderr, "unknown notification provider: %s\n", qUtf8Printable(args.first()));
            return 2;
        }
        const QString cat = QStringLiteral("notif_") + def->id;
        auto r = repo.set(cat + QStringLiteral(".enabled"), sub == "enable" ? QStringLiteral("1") : QStringLiteral("0"), cat);
        if (r.is_err()) {
            std::fprintf(stderr, "failed to update provider: %s\n", r.error().c_str());
            return 5;
        }
        svc.reload_all_configs();
        return emit_mutation_body(opts, mutation_body(sub == "enable" ? QStringLiteral("Notification provider enabled")
                                                                      : QStringLiteral("Notification provider disabled"),
                                                      QJsonObject{{"provider", def->id}}));
    }

    if (sub == "clear") {
        if (!require_yes(args, "usage: notify clear <provider> [field|all] --yes"))
            return 2;
        if (args.size() < 1 || args.size() > 2) {
            std::fprintf(stderr, "usage: notify clear <provider> [field|all] --yes\n");
            return 2;
        }
        const auto def = notify_provider_def(args.takeFirst());
        if (!def) {
            std::fprintf(stderr, "unknown notification provider\n");
            return 2;
        }
        const QString cat = QStringLiteral("notif_") + def->id;
        QString field = args.isEmpty() ? QStringLiteral("all") : args.first().trimmed();
        if (field == "all") {
            auto r = repo.clear_category(cat);
            if (r.is_err()) {
                std::fprintf(stderr, "failed to clear provider: %s\n", r.error().c_str());
                return 5;
            }
        } else {
            if (!notify_field_exists(*def, field) || field == "enabled") {
                std::fprintf(stderr, "unknown clearable field for %s: %s\n", qUtf8Printable(def->id), qUtf8Printable(field));
                return 2;
            }
            auto r = repo.remove(cat + QStringLiteral(".") + field);
            if (r.is_err()) {
                std::fprintf(stderr, "failed to clear provider field: %s\n", r.error().c_str());
                return 5;
            }
        }
        svc.reload_all_configs();
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Notification provider config cleared"),
                                                      QJsonObject{{"provider", def->id}, {"field", field}}));
    }

    if (sub == "triggers") {
        if (args.isEmpty())
            return emit_notify_triggers(opts);
        if (!require_yes(args, "usage: notify triggers key=value ... --yes"))
            return 2;
        const QMap<QString, QString> keys{{"inapp", "notifications.inapp"},
                                          {"price_alerts", "notifications.price_alerts"},
                                          {"price", "notifications.price_alerts"},
                                          {"news_alerts", "notifications.news_alerts"},
                                          {"news", "notifications.news_alerts"},
                                          {"order_fills", "notifications.order_fills"},
                                          {"orders", "notifications.order_fills"},
                                          {"news_breaking", "notifications.news_breaking"},
                                          {"news_monitors", "notifications.news_monitors"},
                                          {"news_deviations", "notifications.news_deviations"},
                                          {"news_flash", "notifications.news_flash"}};
        for (const QString& tok : args) {
            const int eq = tok.indexOf('=');
            if (eq <= 0) {
                std::fprintf(stderr, "expected key=value: %s\n", qUtf8Printable(tok));
                return 2;
            }
            const QString key = tok.left(eq).trimmed().toLower();
            if (!keys.contains(key)) {
                std::fprintf(stderr, "unknown notification trigger: %s\n", qUtf8Printable(key));
                return 2;
            }
            auto r = repo.set(keys.value(key), parse_cli_bool(tok.mid(eq + 1)) ? QStringLiteral("1") : QStringLiteral("0"),
                              QStringLiteral("notifications"));
            if (r.is_err()) {
                std::fprintf(stderr, "failed to update trigger: %s\n", r.error().c_str());
                return 5;
            }
        }
        return emit_mutation_body(opts, mutation_body(QStringLiteral("Notification triggers updated"), notify_triggers_json()));
    }

    if (sub == "send" || sub == "test") {
        QString provider_id;
        QString title;
        QString message;
        QString level_raw = QStringLiteral("info");
        QString timeout_raw;
        const bool all = take_bool_flag(args, QStringLiteral("--all"));
        if (!take_string_option(args, QStringLiteral("--provider"), provider_id) ||
            !take_string_option(args, QStringLiteral("--title"), title) ||
            !take_string_option(args, QStringLiteral("--message"), message) ||
            !take_string_option(args, QStringLiteral("--level"), level_raw) ||
            !take_string_option(args, QStringLiteral("--timeout-sec"), timeout_raw))
            return 2;
        if (!require_yes(args, sub == "test" ? "usage: notify test <provider> [--timeout-sec N] --yes"
                                             : "usage: notify send (--provider P | --all) --title T --message M --yes"))
            return 2;
        if (sub == "test") {
            if (!provider_id.isEmpty() || all || args.size() != 1) {
                std::fprintf(stderr, "usage: notify test <provider> [--timeout-sec N] --yes\n");
                return 2;
            }
            provider_id = args.takeFirst();
            title = QStringLiteral("OpenMarketTerminal Test");
            message = QStringLiteral("This is a test notification from OpenMarketTerminal.");
        }
        if (sub == "send" && (title.isEmpty() || message.isEmpty() || (provider_id.isEmpty() == !all) || !args.isEmpty())) {
            std::fprintf(stderr, "usage: notify send (--provider P | --all) --title T --message M [--level L] [--timeout-sec N] --yes\n");
            return 2;
        }
        bool level_ok = false;
        const auto level = parse_notify_level(level_raw, level_ok);
        if (!level_ok) {
            std::fprintf(stderr, "--level must be info, warning, alert, or critical\n");
            return 2;
        }
        bool timeout_ok = true;
        int timeout_ms = 15000;
        if (!timeout_raw.isEmpty()) {
            const int sec = timeout_raw.toInt(&timeout_ok);
            if (!timeout_ok || sec <= 0 || sec > 300) {
                std::fprintf(stderr, "--timeout-sec must be 1..300\n");
                return 2;
            }
            timeout_ms = sec * 1000;
        }
        notifications::NotificationRequest req;
        req.title = title;
        req.message = message;
        req.level = level;
        req.trigger = notifications::NotifTrigger::Manual;

        QVector<notifications::INotificationProvider*> targets;
        if (all) {
            for (auto* p : svc.providers()) {
                if (p->is_enabled() && p->is_configured())
                    targets.append(p);
            }
        } else {
            auto* p = svc.provider(provider_id.trimmed().toLower());
            if (!p) {
                std::fprintf(stderr, "unknown notification provider: %s\n", qUtf8Printable(provider_id));
                return 2;
            }
            targets.append(p);
        }
        if (targets.isEmpty()) {
            std::fprintf(stderr, "no enabled and configured notification providers\n");
            return 5;
        }
        QJsonArray results;
        int failures = 0;
        for (auto* p : targets) {
            bool send_ok = false;
            QString error;
            notify_wait_send(p, req, timeout_ms, send_ok, error);
            if (!send_ok)
                ++failures;
            results.append(QJsonObject{{"provider", p->provider_id()},
                                       {"ok", send_ok},
                                       {"error", error},
                                       {"level", notify_level_text(level)}});
            if (!opts.json)
                std::printf("%-14s %s%s%s\n",
                            qUtf8Printable(p->provider_id()),
                            send_ok ? "sent" : "failed",
                            error.isEmpty() ? "" : "  ",
                            qUtf8Printable(error));
        }
        if (opts.json)
            std::printf("%s\n", QJsonDocument(QJsonObject{{"results", results},
                                                         {"ok", failures == 0}})
                                    .toJson(QJsonDocument::Compact).constData());
        return failures == 0 ? 0 : 5;
    }

    std::fprintf(stderr, "usage: notify providers|status|config|set|clear|enable|disable|triggers|send|test\n");
    return 2;
}

static QString scanner_ms(qint64 ms) {
    if (ms <= 0)
        return {};
    return QDateTime::fromMSecsSinceEpoch(ms).toString(Qt::ISODate);
}

static QJsonObject scanner_watch_to_json(const ScanWatch& w) {
    return QJsonObject{{"id", w.id},
                       {"name", w.name},
                       {"conditions", w.conditions},
                       {"logic", w.logic},
                       {"symbols", QJsonArray::fromStringList(w.symbols)},
                       {"universe", w.universe},
                       {"timeframe", w.timeframe},
                       {"lookback_days", w.lookback_days},
                       {"data_source", w.data_source},
                       {"broker_id", w.broker_id},
                       {"account_id", w.account_id},
                       {"mode", w.mode},
                       {"interval_sec", w.interval_sec},
                       {"cooldown_min", w.cooldown_min},
                       {"actions", w.actions},
                       {"active", w.active},
                       {"status", w.status},
                       {"last_eval_at", w.last_eval_at},
                       {"last_eval_time", scanner_ms(w.last_eval_at)},
                       {"last_fired_at", w.last_fired_at},
                       {"last_fired_time", scanner_ms(w.last_fired_at)}};
}

static QJsonObject scanner_event_to_json(const ScanWatchEvent& e) {
    return QJsonObject{{"id", e.id},
                       {"watch_id", e.watch_id},
                       {"symbol", e.symbol},
                       {"detail", e.detail},
                       {"fired_at", e.fired_at},
                       {"fired_time", scanner_ms(e.fired_at)}};
}

static int emit_scanner_watches(const GlobalOpts& opts, const QVector<ScanWatch>& watches) {
    if (opts.json) {
        QJsonArray arr;
        for (const auto& w : watches)
            arr.append(scanner_watch_to_json(w));
        std::printf("%s\n", QJsonDocument(QJsonObject{{"watches", arr}}).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    if (watches.isEmpty()) {
        std::printf("no scanner watches\n");
        return 0;
    }
    std::printf("%-36s %-6s %-10s %-6s %-8s %-12s %s\n", "id", "active", "status", "tf", "interval", "symbols", "name");
    for (const auto& w : watches) {
        std::printf("%-36s %-6s %-10s %-6s %-8d %-12s %s\n",
                    qUtf8Printable(w.id),
                    w.active ? "yes" : "no",
                    qUtf8Printable(elide_text(w.status, 10)),
                    qUtf8Printable(w.timeframe),
                    w.interval_sec,
                    qUtf8Printable(elide_text(w.symbols.join(','), 12)),
                    qUtf8Printable(elide_text(w.name, 80)));
    }
    return 0;
}

static int emit_scanner_watch_detail(const GlobalOpts& opts, const ScanWatch& w) {
    const QJsonObject obj = scanner_watch_to_json(w);
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(obj).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("id             %s\n", qUtf8Printable(w.id));
    std::printf("name           %s\n", qUtf8Printable(w.name));
    std::printf("active         %s\n", w.active ? "yes" : "no");
    std::printf("status         %s\n", qUtf8Printable(w.status));
    std::printf("symbols        %s\n", qUtf8Printable(w.symbols.join(',')));
    std::printf("universe       %s\n", qUtf8Printable(w.universe));
    std::printf("timeframe      %s\n", qUtf8Printable(w.timeframe));
    std::printf("interval_sec   %d\n", w.interval_sec);
    std::printf("cooldown_min   %d\n", w.cooldown_min);
    std::printf("notify         %s\n", w.actions.value("providers").toBool(false) ? "yes" : "no");
    std::printf("toast          %s\n", w.actions.value("toast").toBool(true) ? "yes" : "no");
    if (w.last_eval_at > 0)
        std::printf("last_eval      %s\n", qUtf8Printable(scanner_ms(w.last_eval_at)));
    if (w.last_fired_at > 0)
        std::printf("last_fired     %s\n", qUtf8Printable(scanner_ms(w.last_fired_at)));
    std::printf("logic          %s\n", qUtf8Printable(w.logic));
    std::printf("conditions     %s\n", QJsonDocument(w.conditions).toJson(QJsonDocument::Compact).constData());
    return 0;
}

static int emit_scanner_events(const GlobalOpts& opts, const QVector<ScanWatchEvent>& events) {
    if (opts.json) {
        QJsonArray arr;
        for (const auto& e : events)
            arr.append(scanner_event_to_json(e));
        std::printf("%s\n", QJsonDocument(QJsonObject{{"events", arr}}).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    if (events.isEmpty()) {
        std::printf("no scanner events\n");
        return 0;
    }
    std::printf("%-24s %-36s %-12s %s\n", "time", "watch_id", "symbol", "detail");
    for (const auto& e : events) {
        std::printf("%-24s %-36s %-12s %s\n",
                    qUtf8Printable(scanner_ms(e.fired_at)),
                    qUtf8Printable(e.watch_id),
                    qUtf8Printable(e.symbol),
                    qUtf8Printable(elide_text(e.detail, 90)));
    }
    return 0;
}

static QStringList scanner_parse_symbols(QString raw) {
    raw.replace(';', ',');
    raw.replace('\n', ',');
    QStringList out;
    for (const QString& part : raw.split(',', Qt::SkipEmptyParts)) {
        const QString sym = part.trimmed().toUpper();
        if (!sym.isEmpty() && !out.contains(sym))
            out << sym;
    }
    return out;
}

static QString scanner_op_from_word(QString word, bool& ok) {
    word = word.trimmed().toLower();
    ok = true;
    if (word == "above" || word == "over" || word == "gt" || word == ">") return QStringLiteral(">");
    if (word == "below" || word == "under" || word == "lt" || word == "<") return QStringLiteral("<");
    if (word == "at" || word == "eq" || word == "equals" || word == "touches" || word == "==") return QStringLiteral("==");
    if (word == "crosses-above" || word == "crosses_above" || word == "cross-above") return QStringLiteral("crosses_above");
    if (word == "crosses-below" || word == "crosses_below" || word == "cross-below") return QStringLiteral("crosses_below");
    if (word == ">=" || word == "gte" || word == "at-or-above") return QStringLiteral(">=");
    if (word == "<=" || word == "lte" || word == "at-or-below") return QStringLiteral("<=");
    ok = false;
    return {};
}

static int crypto_latency_emit(const GlobalOpts& opts,
                               const services::crypto_latency::CryptoLatencySnapshot& snapshot) {
    using services::crypto_latency::CryptoLatencyService;
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(CryptoLatencyService::snapshot_to_json(snapshot))
                                .toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("symbol       %s\n", qUtf8Printable(snapshot.symbol));
    std::printf("freshest     %s age=%lldms live_sources=%d spread=%.3fbps\n",
                qUtf8Printable(snapshot.freshest_source.isEmpty() ? QStringLiteral("-") : snapshot.freshest_source),
                static_cast<long long>(snapshot.freshest_age_ms),
                snapshot.live_sources,
                snapshot.cross_source_spread_bps);
    std::printf("%-10s %-12s %-14s %-8s %-10s %-10s %s\n",
                "source", "status", "price", "age", "ticks", "messages", "last/error");
    const qint64 now = QDateTime::currentMSecsSinceEpoch();
    QHash<QString, services::crypto_latency::CryptoLatencyTick> latest;
    for (const auto& t : snapshot.latest_ticks)
        latest.insert(t.source, t);
    for (const auto& s : snapshot.sources) {
        const auto t = latest.value(s.source);
        const qint64 age = s.last_tick_ms > 0 ? now - s.last_tick_ms : -1;
        const QString last = s.error.isEmpty() ? s.last_message_type : s.error;
        std::printf("%-10s %-12s %-14s %-8lld %-10d %-10d %s\n",
                    qUtf8Printable(s.source),
                    qUtf8Printable(s.status),
                    qUtf8Printable(t.price > 0.0 ? QString::number(t.price, 'f', t.price < 10 ? 4 : 2)
                                                  : QStringLiteral("-")),
                    static_cast<long long>(age),
                    s.ticks,
                    s.raw_messages,
                    qUtf8Printable(last));
    }
    return 0;
}

static int crypto_latency_command(const GlobalOpts& opts, QStringList args) {
    using services::crypto_latency::CryptoLatencyService;
    const QString sub = args.isEmpty() ? QStringLiteral("sample") : args.takeFirst().trimmed().toLower();
    if (sub != QStringLiteral("sample") && sub != QStringLiteral("snapshot") && sub != QStringLiteral("watch")) {
        std::fprintf(stderr, "usage: crypto-latency sample BTC-USD [--sources coinbase,kraken,binanceus,bitcointicker] [--duration-ms N] [--min-live-sources N]\n");
        return 2;
    }

    QString duration_raw;
    QString sources_raw;
    QString ticks_raw;
    QString live_sources_raw;
    if (!take_string_option(args, QStringLiteral("--duration-ms"), duration_raw) ||
        !take_string_option(args, QStringLiteral("--sources"), sources_raw) ||
        !take_string_option(args, QStringLiteral("--min-ticks"), ticks_raw) ||
        !take_string_option(args, QStringLiteral("--min-live-sources"), live_sources_raw))
        return 2;

    int duration_ms = sub == QStringLiteral("watch") ? 10000 : 3000;
    if (!duration_raw.isEmpty()) {
        bool ok = false;
        duration_ms = duration_raw.toInt(&ok);
        if (!ok || duration_ms < 250 || duration_ms > 60000) {
            std::fprintf(stderr, "--duration-ms must be 250..60000\n");
            return 2;
        }
    }
    int min_ticks = 1;
    if (!ticks_raw.isEmpty()) {
        bool ok = false;
        min_ticks = ticks_raw.toInt(&ok);
        if (!ok || min_ticks < 0) {
            std::fprintf(stderr, "--min-ticks must be non-negative\n");
            return 2;
        }
    }

    const QString symbol = args.isEmpty() ? QStringLiteral("BTC-USD") : args.takeFirst();
    if (!args.isEmpty()) {
        std::fprintf(stderr, "unknown args: %s\n", qUtf8Printable(args.join(' ')));
        return 2;
    }
    QStringList sources;
    if (sources_raw.trimmed().isEmpty()) {
        sources = CryptoLatencyService::default_sources();
    } else {
        for (const auto& piece : sources_raw.split(',', Qt::SkipEmptyParts)) {
            const QString s = piece.trimmed().toLower();
            if (!s.isEmpty() && !sources.contains(s))
                sources << s;
        }
    }
    const int source_count = static_cast<int>(sources.size());
    int min_live_sources = std::min(2, std::max(1, source_count));
    if (!live_sources_raw.isEmpty()) {
        bool ok = false;
        min_live_sources = live_sources_raw.toInt(&ok);
        if (!ok || min_live_sources < 0 || min_live_sources > source_count) {
            std::fprintf(stderr, "--min-live-sources must be between 0 and source count\n");
            return 2;
        }
    }

    CryptoLatencyService service;
    QEventLoop loop;
    QTimer timeout;
    timeout.setSingleShot(true);
    int observed_ticks = 0;
    QObject::connect(&service, &CryptoLatencyService::tick_received, &loop,
                     [&](const services::crypto_latency::CryptoLatencyTick&) {
                         observed_ticks += 1;
                         const int live = service.snapshot().live_sources;
                         if (min_ticks > 0 && observed_ticks >= min_ticks &&
                             live >= min_live_sources && sub != QStringLiteral("watch"))
                             QTimer::singleShot(250, &loop, &QEventLoop::quit);
                     });
    QObject::connect(&timeout, &QTimer::timeout, &loop, &QEventLoop::quit);

    service.start(symbol, sources);
    timeout.start(duration_ms);
    loop.exec();
    const auto snapshot = service.snapshot();
    service.stop();
    return crypto_latency_emit(opts, snapshot);
}

static QString edge_pct(double v) {
    return QString::number(v * 100.0, 'f', 2) + QStringLiteral("%");
}

static bool edge_parse_probability(QStringList& args, const QString& flag, double& out, bool required) {
    QString raw;
    if (!take_string_option(args, flag, raw))
        return false;
    if (raw.isEmpty()) {
        if (required)
            std::fprintf(stderr, "%s is required\n", qUtf8Printable(flag));
        return !required;
    }
    bool ok = false;
    double value = raw.toDouble(&ok);
    if (!ok) {
        std::fprintf(stderr, "%s must be a number\n", qUtf8Printable(flag));
        return false;
    }
    if (value > 1.0)
        value /= 100.0;
    if (value < 0.0 || value > 1.0) {
        std::fprintf(stderr, "%s must be between 0 and 1, or 0 and 100 percent\n", qUtf8Printable(flag));
        return false;
    }
    out = value;
    return true;
}

static bool edge_parse_cost(QStringList& args, const QString& flag, double& out) {
    QString raw;
    if (!take_string_option(args, flag, raw))
        return false;
    if (raw.isEmpty())
        return true;
    bool ok = false;
    const double pct_points = raw.toDouble(&ok);
    if (!ok || pct_points < 0.0 || pct_points > 100.0) {
        std::fprintf(stderr, "%s must be a non-negative percent-point number\n", qUtf8Printable(flag));
        return false;
    }
    out = pct_points / 100.0;
    return true;
}

static QJsonObject edge_score_json_from_idea(const EdgeRadarIdea& idea) {
    QJsonObject obj = edge_radar_idea_to_json(idea);
    obj.insert(QStringLiteral("market_probability_percent"), edge_pct(idea.market_probability));
    obj.insert(QStringLiteral("model_probability_percent"), edge_pct(idea.model_probability));
    obj.insert(QStringLiteral("raw_edge_percent"), edge_pct(idea.raw_edge));
    obj.insert(QStringLiteral("edge_after_cost_percent"), edge_pct(idea.edge_after_cost));
    return obj;
}

static EdgeRadarIdea edge_apply_score(EdgeRadarIdea idea) {
    const auto score = services::edge_radar::EdgeRadarService::evaluate(
        {idea.market_probability, idea.model_probability, idea.spread_cost, idea.fee_cost,
         idea.liquidity_score, idea.confidence});
    idea.side = score.side;
    idea.raw_edge = score.raw_edge;
    idea.edge_after_cost = score.edge_after_cost;
    idea.recommendation = score.recommendation;
    if (idea.risk_notes.trimmed().isEmpty())
        idea.risk_notes = score.risk_notes;
    idea.last_evaluated_at = QDateTime::currentMSecsSinceEpoch();
    return idea;
}

static bool edge_parse_probability_text(const QString& raw, double& out) {
    bool ok = false;
    double value = raw.trimmed().toDouble(&ok);
    if (!ok)
        return false;
    if (value > 1.0)
        value /= 100.0;
    if (value < 0.0 || value > 1.0)
        return false;
    out = value;
    return true;
}

static int edge_emit_crypto_hourly(const GlobalOpts& opts,
                                   const QVector<services::edge_radar::CryptoHourlySignal>& rows) {
    if (opts.json) {
        QJsonArray arr;
        for (const auto& r : rows)
            arr.append(services::edge_radar::CryptoHourlyEdgeModel::to_json(r));
        std::printf("%s\n", QJsonDocument(QJsonObject{{"signals", arr}}).toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    if (rows.isEmpty()) {
        std::printf("no crypto-hourly signals\n");
        return 0;
    }
    std::printf("%-8s %-8s %-8s %-8s %-8s %-10s %s\n",
                "symbol", "market", "model", "gate", "side", "call", "rationale");
    for (const auto& r : rows) {
        std::printf("%-8s %-8s %-8s %-8s %-8s %-10s %s\n",
                    qUtf8Printable(r.symbol),
                    qUtf8Printable(edge_pct(r.market_probability)),
                    qUtf8Printable(edge_pct(r.model_probability)),
                    qUtf8Printable(edge_pct(r.gate_edge)),
                    qUtf8Printable(elide_text(r.side, 8)),
                    qUtf8Printable(r.recommendation),
                    qUtf8Printable(r.rejection_reasons.isEmpty() ? r.rationale : r.rejection_reasons));
    }
    return 0;
}

static QStringList edge_parse_latency_sources(const QString& raw) {
    using services::crypto_latency::CryptoLatencyService;
    if (raw.trimmed().isEmpty())
        return CryptoLatencyService::default_sources();
    QStringList sources;
    for (const auto& piece : raw.split(',', Qt::SkipEmptyParts)) {
        const QString s = piece.trimmed().toLower();
        if (!s.isEmpty() && !sources.contains(s))
            sources << s;
    }
    return sources.isEmpty() ? CryptoLatencyService::default_sources() : sources;
}

static QString edge_base_crypto_symbol(QString symbol) {
    QString s = symbol.trimmed().toUpper();
    s.replace('/', '-');
    for (const QString& suffix : {QStringLiteral("-USD"), QStringLiteral("-USDT"),
                                  QStringLiteral("-USDC"), QStringLiteral("USD"),
                                  QStringLiteral("USDT"), QStringLiteral("USDC")}) {
        if (s.endsWith(suffix)) {
            s.chop(suffix.size());
            break;
        }
    }
    return s.isEmpty() ? symbol.trimmed().toUpper() : s;
}

static QStringList edge_safe_latency_sources_for_symbol(const QString& raw, const QString& symbol) {
    QStringList sources = edge_parse_latency_sources(raw);
    if (edge_base_crypto_symbol(symbol) != QLatin1String("BTC"))
        sources.removeAll(QStringLiteral("bitcointicker"));
    if (sources.isEmpty())
        sources = {QStringLiteral("coinbase"), QStringLiteral("kraken"), QStringLiteral("binanceus")};
    return sources;
}

static bool edge_parse_duration_ms(const QString& raw, int& duration_ms) {
    if (raw.isEmpty())
        return true;
    bool ok = false;
    duration_ms = raw.toInt(&ok);
    if (!ok || duration_ms < 1000 || duration_ms > 120000) {
        std::fprintf(stderr, "--duration-ms must be 1000..120000\n");
        return false;
    }
    return true;
}

static bool edge_parse_window_seconds(const QString& raw, int& seconds) {
    if (raw.isEmpty())
        return true;
    QString s = raw.trimmed().toLower();
    if (s.endsWith('s'))
        s.chop(1);
    bool ok = false;
    const int parsed = s.toInt(&ok);
    if (!ok || (parsed != 5 && parsed != 15 && parsed != 60)) {
        std::fprintf(stderr, "--window must be 5s, 15s, or 60s\n");
        return false;
    }
    seconds = parsed;
    return true;
}

static services::edge_radar::CryptoImpulseSignal edge_capture_impulse(const QString& symbol,
                                                                      const QStringList& sources,
                                                                      int duration_ms,
                                                                      int window_seconds,
                                                                      const services::edge_radar::CryptoImpulseOptions& options) {
    using services::crypto_latency::CryptoLatencyService;
    using services::edge_radar::CryptoImpulseModel;

    CryptoLatencyService service;
    CryptoImpulseModel model(options);
    QEventLoop loop;
    QTimer timeout;
    timeout.setSingleShot(true);
    QObject::connect(&service, &CryptoLatencyService::tick_received, &loop,
                     [&](const services::crypto_latency::CryptoLatencyTick& tick) {
                         model.add_tick(tick);
                     });
    QObject::connect(&timeout, &QTimer::timeout, &loop, &QEventLoop::quit);
    service.start(symbol, sources);
    timeout.start(duration_ms);
    loop.exec();
    service.stop();
    return model.signal(window_seconds);
}

static int edge_emit_impulse(const GlobalOpts& opts,
                             const services::edge_radar::CryptoImpulseSignal& signal) {
    using services::edge_radar::CryptoImpulseModel;
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(CryptoImpulseModel::to_json(signal))
                                .toJson(QJsonDocument::Compact).constData());
        return 0;
    }
    std::printf("symbol       %s\n", qUtf8Printable(signal.symbol));
    std::printf("impulse      %s %s confidence=%.2f gate=%s call=%s\n",
                qUtf8Printable(signal.direction),
                qUtf8Printable(signal.strength),
                signal.confidence,
                qUtf8Printable(signal.gate),
                qUtf8Printable(signal.recommendation));
    std::printf("freshest     %s age=%lldms anchor=%s\n",
                qUtf8Printable(signal.freshest_source.isEmpty() ? QStringLiteral("-") : signal.freshest_source),
                static_cast<long long>(signal.latest_tick_age_ms),
                qUtf8Printable(edge_pct(CryptoImpulseModel::anchor_probability(signal))));
    for (const auto& w : signal.windows) {
        std::printf("%2ds window  %s move=%s velocity=%s%%/s price=%s -> %s\n",
                    w.seconds,
                    w.available ? "ok " : "wait",
                    qUtf8Printable(w.available ? QStringLiteral("%1%").arg(w.move_pct, 0, 'f', 3)
                                                : QStringLiteral("-")),
                    qUtf8Printable(w.available ? QString::number(w.velocity_pct_per_sec, 'f', 4)
                                                : QStringLiteral("-")),
                    qUtf8Printable(w.available ? QString::number(w.start_price, 'f', w.start_price < 10 ? 4 : 2)
                                                : QStringLiteral("-")),
                    qUtf8Printable(w.available ? QString::number(w.end_price, 'f', w.end_price < 10 ? 4 : 2)
                                                : QStringLiteral("-")));
    }
    std::printf("rationale    %s\n", qUtf8Printable(signal.rationale));
    if (!signal.rejection_reasons.isEmpty())
        std::printf("no-trade     %s\n", qUtf8Printable(signal.rejection_reasons));
    return 0;
}

static services::edge_radar::CryptoMicrostructureSnapshot
edge_capture_microstructure(const QString& symbol,
                            const QStringList& sources,
                            int duration_ms,
                            bool store_raw_ticks = false) {
    using services::crypto_latency::CryptoLatencyService;
    using services::edge_radar::CryptoMicrostructureRadar;

    CryptoLatencyService service;
    CryptoMicrostructureRadar radar;
    QEventLoop loop;
    QTimer timeout;
    timeout.setSingleShot(true);
    QObject::connect(&service, &CryptoLatencyService::tick_received, &loop,
                     [&](const services::crypto_latency::CryptoLatencyTick& tick) {
                         radar.add_tick(tick);
                         if (store_raw_ticks && tick.price > 0.0) {
                             EdgePredictionRawTick raw;
                             raw.id = QStringLiteral("micro:%1:%2:%3:%4")
                                          .arg(tick.source,
                                               edge_base_crypto_symbol(symbol),
                                               QString::number(tick.received_ts_ms),
                                               QString::number(tick.sequence));
                             raw.symbol = edge_base_crypto_symbol(symbol);
                             raw.source = tick.source;
                             raw.price = tick.price;
                             raw.exchange_ts = tick.exchange_ts_ms;
                             raw.received_ts = tick.received_ts_ms;
                             EdgePredictionModelRepository::instance().add_raw_tick(raw);
                         }
                     });
    QObject::connect(&timeout, &QTimer::timeout, &loop, &QEventLoop::quit);
    service.start(symbol, sources);
    timeout.start(duration_ms);
    loop.exec();
    const auto snapshot = radar.snapshot(service.snapshot());
    service.stop();
    return snapshot;
}

static QString edge_price_or_dash(double price) {
    return price > 0.0 ? QString::number(price, 'f', price < 10.0 ? 4 : 2)
                       : QStringLiteral("-");
}

static int edge_emit_microstructure(const GlobalOpts& opts,
                                    const services::edge_radar::CryptoMicrostructureSnapshot& snapshot) {
    using services::edge_radar::CryptoMicrostructureRadar;
    if (opts.json) {
        std::printf("%s\n", QJsonDocument(CryptoMicrostructureRadar::to_json(snapshot))
                                .toJson(QJsonDocument::Compact).constData());
        return 0;
    }

    std::printf("symbol       %s\n", qUtf8Printable(snapshot.symbol));
    std::printf("call         %s direction=%s confidence=%s\n",
                qUtf8Printable(snapshot.call),
                qUtf8Printable(snapshot.direction),
                qUtf8Printable(edge_pct(snapshot.confidence)));
    std::printf("freshest     %s age=%lldms live_sources=%d divergence=%.2fbps\n",
                qUtf8Printable(snapshot.freshest_source.isEmpty() ? QStringLiteral("-") : snapshot.freshest_source),
                static_cast<long long>(snapshot.freshest_age_ms),
                snapshot.live_sources,
                snapshot.cross_source_spread_bps);
    std::printf("pressure     tape=%+.2f book=%+.2f ticks=%d\n",
                snapshot.tape_pressure,
                snapshot.book_pressure,
                snapshot.tick_count);

    std::printf("\nSOURCES\n");
    std::printf("%-13s %-11s %12s %12s %12s %9s %8s %s\n",
                "SOURCE", "STATUS", "BID", "ASK", "PRICE", "SPREAD", "AGE", "MSG");
    for (const auto& s : snapshot.sources) {
        std::printf("%-13s %-11s %12s %12s %12s %8.2f %7lldms %s\n",
                    qUtf8Printable(s.source),
                    qUtf8Printable(s.status),
                    qUtf8Printable(edge_price_or_dash(s.best_bid)),
                    qUtf8Printable(edge_price_or_dash(s.best_ask)),
                    qUtf8Printable(edge_price_or_dash(s.price)),
                    s.spread_bps,
                    static_cast<long long>(s.age_ms),
                    qUtf8Printable(s.message.left(32)));
    }

    std::printf("\nWINDOWS\n");
    std::printf("%-8s %8s %8s %8s %10s %12s %12s\n",
                "WINDOW", "UP", "DOWN", "FLAT", "PRESSURE", "MOVE", "PRICE");
    for (const auto& w : snapshot.windows) {
        std::printf("%-8s %8d %8d %8d %10.2f %11s %12s\n",
                    qUtf8Printable(QStringLiteral("%1s").arg(w.seconds)),
                    w.upticks,
                    w.downticks,
                    w.flat_ticks,
                    w.tape_pressure,
                    qUtf8Printable(w.available ? QStringLiteral("%1%").arg(w.move_pct, 0, 'f', 3)
                                                : QStringLiteral("-")),
                    qUtf8Printable(w.available
                                        ? QStringLiteral("%1>%2")
                                              .arg(edge_price_or_dash(w.start_price), edge_price_or_dash(w.end_price))
                                        : QStringLiteral("-")));
    }
    std::printf("\nrationale    %s\n", qUtf8Printable(snapshot.rationale));
    return 0;
}

static int edge_microstructure_command(const GlobalOpts& opts, QStringList args) {
    QString duration_raw;
    QString sources_raw;
    QString interval_raw;
    QString iterations_raw;
    const bool watch = take_bool_flag(args, QStringLiteral("--watch"));
    if (!take_string_option(args, QStringLiteral("--duration-ms"), duration_raw) ||
        !take_string_option(args, QStringLiteral("--sources"), sources_raw) ||
        !take_string_option(args, QStringLiteral("--interval-sec"), interval_raw) ||
        !take_string_option(args, QStringLiteral("--iterations"), iterations_raw))
        return 2;

    int duration_ms = watch ? 4000 : 8000;
    if (!edge_parse_duration_ms(duration_raw, duration_ms))
        return 2;
    int interval_sec = 5;
    if (!interval_raw.isEmpty()) {
        bool ok = false;
        interval_sec = interval_raw.toInt(&ok);
        if (!ok || interval_sec < 1 || interval_sec > 3600) {
            std::fprintf(stderr, "--interval-sec must be 1..3600\n");
            return 2;
        }
    }
    int iterations = watch ? 0 : 1;
    if (!iterations_raw.isEmpty()) {
        bool ok = false;
        iterations = iterations_raw.toInt(&ok);
        if (!ok || iterations < 1 || iterations > 100000) {
            std::fprintf(stderr, "--iterations must be 1..100000\n");
            return 2;
        }
    }

    const QString symbol = args.isEmpty() ? QStringLiteral("BTC-USD") : args.takeFirst();
    if (!args.isEmpty()) {
        std::fprintf(stderr, "unknown args: %s\n", qUtf8Printable(args.join(' ')));
        return 2;
    }

    int rendered = 0;
    while (iterations == 0 || rendered < iterations) {
        if (watch && !opts.json)
            std::printf("\033[2J\033[H");
        const auto snapshot = edge_capture_microstructure(
            services::crypto_latency::CryptoLatencyService::normalize_symbol(symbol),
            edge_parse_latency_sources(sources_raw),
            duration_ms);
        const int rc = edge_emit_microstructure(opts, snapshot);
        std::fflush(stdout);
        if (rc != 0 || opts.json)
            return rc;
        ++rendered;
        if (iterations > 0 && rendered >= iterations)
            break;
        if (watch)
            std::printf("\nwatch        refreshing every %ds; press Ctrl-C to stop\n", interval_sec);
        QThread::sleep(static_cast<unsigned long>(interval_sec));
    }
    return 0;
}

struct CryptoRecommendationDecision {
    QString id;
    QString symbol;
    QString venue;
    QString horizon;
    QString direction;
    QString side;
    QString call;
    QString gate;
    QString data_status;
    QString rationale;
    double market_probability = 0.5;
    double model_probability = 0.5;
    double raw_edge = 0.0;
    double edge_after_cost = 0.0;
    double gate_edge = 0.0;
    double spread_cost = 0.0;
    double fee_cost = 0.0;
    double slippage_cost = 0.0;
    double liquidity_score = 0.0;
    double confidence = 0.0;
    double reference_price = 0.0;
    int seconds_left = 0;
};

static bool edge_parse_bps_text(const QString& raw, double& out, const char* flag) {
    if (raw.isEmpty())
        return true;
    bool ok = false;
    const double value = raw.trimmed().toDouble(&ok);
    if (!ok || value < 0.0 || value > 10000.0) {
        std::fprintf(stderr, "%s must be 0..10000 bps\n", flag);
        return false;
    }
    out = value;
    return true;
}

static CryptoRecommendationDecision edge_score_crypto_recommendation(
    const QString& symbol,
    const QString& venue,
    const services::edge_radar::CryptoMicrostructureSnapshot& snapshot,
    int horizon_sec,
    double fee_bps,
    double slippage_bps,
    double min_edge_bps) {
    CryptoRecommendationDecision decision;
    decision.symbol = symbol;
    decision.venue = crypto_fee_venue_key(venue);
    decision.horizon = QStringLiteral("%1s").arg(horizon_sec);
    decision.direction = snapshot.direction.isEmpty() ? QStringLiteral("flat") : snapshot.direction;
    decision.reference_price = snapshot.reference_price;
    decision.confidence = std::clamp(snapshot.confidence, 0.0, 1.0);
    decision.seconds_left = horizon_sec;
    decision.spread_cost = std::max(0.0, snapshot.cross_source_spread_bps) / 10000.0;
    decision.fee_cost = std::max(0.0, fee_bps) / 10000.0;
    decision.slippage_cost = std::max(0.0, slippage_bps) / 10000.0;
    decision.gate_edge = std::max(0.0, min_edge_bps) / 10000.0;
    decision.liquidity_score = std::clamp(snapshot.live_sources / 3.0, 0.0, 1.0);

    if (decision.direction == QLatin1String("up")) {
        decision.model_probability = std::min(0.72, 0.50 + decision.confidence * 0.22);
        decision.side = QStringLiteral("buy");
        decision.raw_edge = decision.model_probability - 0.50;
    } else if (decision.direction == QLatin1String("down")) {
        decision.model_probability = std::max(0.28, 0.50 - decision.confidence * 0.22);
        decision.side = QStringLiteral("avoid_buy");
        decision.raw_edge = (1.0 - decision.model_probability) - 0.50;
    } else {
        decision.model_probability = 0.50;
        decision.side = QStringLiteral("hold");
        decision.raw_edge = 0.0;
    }

    decision.edge_after_cost = decision.raw_edge - decision.spread_cost - decision.fee_cost - decision.slippage_cost;

    QStringList reasons;
    if (!snapshot.rationale.isEmpty())
        reasons << snapshot.rationale;
    if (snapshot.freshest_age_ms > 5000)
        reasons << QStringLiteral("freshest tick is stale");
    if (snapshot.live_sources < 2)
        reasons << QStringLiteral("needs at least two live sources");
    if (snapshot.cross_source_spread_bps > 12.0)
        reasons << QStringLiteral("cross-source divergence is too wide");
    if (decision.direction == QLatin1String("flat"))
        reasons << QStringLiteral("microstructure direction is flat");
    if (decision.edge_after_cost < decision.gate_edge)
        reasons << QStringLiteral("estimated edge after fees/spread/slippage is below gate");

    if (snapshot.freshest_age_ms > 5000 || snapshot.live_sources < 2) {
        decision.call = QStringLiteral("NO BUY");
        decision.gate = QStringLiteral("reject");
        decision.data_status = QStringLiteral("not_enough_data");
    } else if (decision.direction == QLatin1String("up") && decision.edge_after_cost >= decision.gate_edge) {
        decision.call = QStringLiteral("BUY CANDIDATE");
        decision.gate = QStringLiteral("pass");
        decision.data_status = QStringLiteral("trade_candidate");
    } else if (decision.direction == QLatin1String("up")) {
        decision.call = QStringLiteral("WATCH");
        decision.gate = QStringLiteral("watch");
        decision.data_status = QStringLiteral("watch");
    } else if (decision.direction == QLatin1String("down")) {
        decision.call = QStringLiteral("NO BUY");
        decision.gate = decision.edge_after_cost >= decision.gate_edge ? QStringLiteral("protect") : QStringLiteral("reject");
        decision.data_status = QStringLiteral("avoid_buy");
    } else {
        decision.call = QStringLiteral("NO BUY");
        decision.gate = QStringLiteral("reject");
        decision.data_status = QStringLiteral("no_trade");
    }
    decision.rationale = reasons.join(QStringLiteral("; "));
    if (decision.rationale.isEmpty())
        decision.rationale = QStringLiteral("microstructure recommendation captured");
    return decision;
}

static int edge_impulse_command(const GlobalOpts& opts, QStringList args) {
    QString duration_raw;
    QString sources_raw;
    QString window_raw;
    QString min_conf_raw;
    if (!take_string_option(args, QStringLiteral("--duration-ms"), duration_raw) ||
        !take_string_option(args, QStringLiteral("--sources"), sources_raw) ||
        !take_string_option(args, QStringLiteral("--window"), window_raw) ||
        !take_string_option(args, QStringLiteral("--min-confidence"), min_conf_raw))
        return 2;

    int duration_ms = 16000;
    int window_seconds = 15;
    if (!edge_parse_duration_ms(duration_raw, duration_ms) ||
        !edge_parse_window_seconds(window_raw, window_seconds))
        return 2;

    services::edge_radar::CryptoImpulseOptions options;
    if (!min_conf_raw.isEmpty() && !edge_parse_probability_text(min_conf_raw, options.minimum_confidence)) {
        std::fprintf(stderr, "--min-confidence must be 0-1 or 0-100\n");
        return 2;
    }

    const QString symbol = args.isEmpty() ? QStringLiteral("BTC-USD") : args.takeFirst();
    if (!args.isEmpty()) {
        std::fprintf(stderr, "unknown args: %s\n", qUtf8Printable(args.join(' ')));
        return 2;
    }
    const auto signal = edge_capture_impulse(
        services::crypto_latency::CryptoLatencyService::normalize_symbol(symbol),
        edge_parse_latency_sources(sources_raw),
        duration_ms,
        window_seconds,
        options);
    return edge_emit_impulse(opts, signal);
}

static int edge_crypto_hourly_command(const GlobalOpts& opts, QStringList args) {
    QString btc_raw;
    QString limit_raw;
    if (!take_string_option(args, QStringLiteral("--btc-prob"), btc_raw) ||
        !take_string_option(args, QStringLiteral("--limit"), limit_raw))
        return 2;

    double btc_prob = 0.0;
    if (btc_raw.isEmpty() || !edge_parse_probability_text(btc_raw, btc_prob)) {
        std::fprintf(stderr, "usage: edge crypto-hourly --btc-prob P --market ETH=P [--market SOL=P] [gate options]\n");
        return 2;
    }

    services::edge_radar::CryptoHourlyOptions options;
    if (!edge_parse_cost(args, QStringLiteral("--spread"), options.spread_cost) ||
        !edge_parse_cost(args, QStringLiteral("--fee"), options.fee_cost) ||
        !edge_parse_cost(args, QStringLiteral("--min-edge"), options.minimum_net_edge) ||
        !edge_parse_cost(args, QStringLiteral("--strong-edge"), options.strong_net_edge) ||
        !edge_parse_cost(args, QStringLiteral("--min-anchor"), options.minimum_anchor_move) ||
        !edge_parse_cost(args, QStringLiteral("--max-cost"), options.maximum_total_cost) ||
        !edge_parse_cost(args, QStringLiteral("--safety-buffer"), options.safety_buffer) ||
        !edge_parse_probability(args, QStringLiteral("--min-liquidity"), options.minimum_liquidity_score, false))
        return 2;

    const bool save_candidates = take_bool_flag(args, QStringLiteral("--save-candidates")) ||
                                 take_bool_flag(args, QStringLiteral("--save"));
    bool yes = false;
    if (save_candidates)
        yes = take_bool_flag(args, QStringLiteral("--yes"));

    QVector<services::edge_radar::CryptoHourlySignal> rows;
    while (true) {
        const int idx = args.indexOf(QStringLiteral("--market"));
        if (idx < 0)
            break;
        if (idx + 1 >= args.size()) {
            std::fprintf(stderr, "--market requires SYMBOL=PROB\n");
            return 2;
        }
        const QString raw = args.takeAt(idx + 1);
        args.removeAt(idx);
        const int eq = raw.indexOf('=');
        if (eq <= 0) {
            std::fprintf(stderr, "--market must look like ETH=49 or SOL=0.52\n");
            return 2;
        }
        const QString symbol = raw.left(eq).trimmed().toUpper();
        double prob = 0.0;
        if (!edge_parse_probability_text(raw.mid(eq + 1), prob)) {
            std::fprintf(stderr, "invalid probability in --market %s\n", qUtf8Printable(raw));
            return 2;
        }
        rows.push_back(services::edge_radar::CryptoHourlyEdgeModel::score_symbol(
            symbol, prob, btc_prob, options, QStringLiteral("up"), 0.0,
            QStringLiteral("%1 hourly crypto contract").arg(symbol), symbol));
    }

    if (!limit_raw.isEmpty()) {
        bool ok = false;
        const int limit = limit_raw.toInt(&ok);
        if (!ok || limit < 1) {
            std::fprintf(stderr, "--limit must be a positive integer\n");
            return 2;
        }
        std::stable_sort(rows.begin(), rows.end(), [](const auto& a, const auto& b) {
            return a.edge_after_cost > b.edge_after_cost;
        });
        while (rows.size() > limit)
            rows.removeLast();
    }

    if (!args.isEmpty()) {
        std::fprintf(stderr, "unknown args: %s\n", qUtf8Printable(args.join(' ')));
        return 2;
    }

    if (save_candidates) {
        if (!yes) {
            std::fprintf(stderr, "usage: edge crypto-hourly ... --save-candidates --yes\n");
            return 2;
        }
        int code = 0;
        if (!init_headless_for_cli(opts, code))
            return code;
        for (const auto& s : rows) {
            if (s.recommendation != QStringLiteral("candidate") &&
                s.recommendation != QStringLiteral("strong"))
                continue;
            EdgeRadarIdea idea;
            idea.asset_class = QStringLiteral("prediction");
            idea.venue = QStringLiteral("kalshi");
            idea.symbol = s.symbol;
            idea.market_id = s.market_id;
            idea.question = s.question;
            idea.market_probability = s.market_probability;
            idea.model_probability = s.model_probability;
            idea.spread_cost = options.spread_cost;
            idea.fee_cost = options.fee_cost;
            idea.liquidity_score = s.liquidity_score;
            idea.confidence = s.confidence;
            idea.side = s.side;
            idea.raw_edge = s.raw_edge;
            idea.edge_after_cost = s.gate_edge;
            idea.recommendation = s.recommendation;
            idea.thesis = s.rationale;
            idea.risk_notes = s.risk_notes;
            idea.status = QStringLiteral("watching");
            idea.tags = s.is_strong
                            ? QStringLiteral("cli,crypto-hourly,btc-anchor,strong")
                            : QStringLiteral("cli,crypto-hourly,btc-anchor");
            auto r = EdgeRadarRepository::instance().create(idea);
            if (r.is_err()) {
                std::fprintf(stderr, "%s\n", r.error().c_str());
                return 5;
            }
        }
    }

    return edge_emit_crypto_hourly(opts, rows);
}

static int edge_emit_crypto_hourly_live(const GlobalOpts& opts,
                                        const services::edge_radar::CryptoImpulseSignal& impulse,
                                        const QVector<services::edge_radar::CryptoHourlySignal>& rows) {
    using services::edge_radar::CryptoHourlyEdgeModel;
    using services::edge_radar::CryptoImpulseModel;
    if (opts.json) {
        QJsonArray arr;
        for (const auto& r : rows)
            arr.append(CryptoHourlyEdgeModel::to_json(r));
        QJsonObject obj{{"impulse", CryptoImpulseModel::to_json(impulse)},
                        {"signals", arr}};
        std::printf("%s\n", QJsonDocument(obj).toJson(QJsonDocument::Compact).constData());
        return 0;
    }

    edge_emit_impulse(opts, impulse);
    std::printf("\n");
    return edge_emit_crypto_hourly(opts, rows);
}

static int edge_crypto_hourly_live_command(const GlobalOpts& opts, QStringList args) {
    QString duration_raw;
    QString sources_raw;
    QString window_raw;
    QString min_conf_raw;
    QString limit_raw;
    QString direction_raw;
    if (!take_string_option(args, QStringLiteral("--duration-ms"), duration_raw) ||
        !take_string_option(args, QStringLiteral("--sources"), sources_raw) ||
        !take_string_option(args, QStringLiteral("--window"), window_raw) ||
        !take_string_option(args, QStringLiteral("--min-confidence"), min_conf_raw) ||
        !take_string_option(args, QStringLiteral("--limit"), limit_raw) ||
        !take_string_option(args, QStringLiteral("--direction"), direction_raw))
        return 2;

    int duration_ms = 16000;
    int window_seconds = 15;
    if (!edge_parse_duration_ms(duration_raw, duration_ms) ||
        !edge_parse_window_seconds(window_raw, window_seconds))
        return 2;

    services::edge_radar::CryptoImpulseOptions impulse_options;
    if (!min_conf_raw.isEmpty() &&
        !edge_parse_probability_text(min_conf_raw, impulse_options.minimum_confidence)) {
        std::fprintf(stderr, "--min-confidence must be 0-1 or 0-100\n");
        return 2;
    }

    services::edge_radar::CryptoHourlyOptions options;
    if (!edge_parse_cost(args, QStringLiteral("--spread"), options.spread_cost) ||
        !edge_parse_cost(args, QStringLiteral("--fee"), options.fee_cost) ||
        !edge_parse_cost(args, QStringLiteral("--min-edge"), options.minimum_net_edge) ||
        !edge_parse_cost(args, QStringLiteral("--strong-edge"), options.strong_net_edge) ||
        !edge_parse_cost(args, QStringLiteral("--min-anchor"), options.minimum_anchor_move) ||
        !edge_parse_cost(args, QStringLiteral("--max-cost"), options.maximum_total_cost) ||
        !edge_parse_cost(args, QStringLiteral("--safety-buffer"), options.safety_buffer) ||
        !edge_parse_probability(args, QStringLiteral("--min-liquidity"), options.minimum_liquidity_score, false))
        return 2;

    QVector<QPair<QString, double>> markets;
    while (true) {
        const int idx = args.indexOf(QStringLiteral("--market"));
        if (idx < 0)
            break;
        if (idx + 1 >= args.size()) {
            std::fprintf(stderr, "--market requires SYMBOL=PROB\n");
            return 2;
        }
        const QString raw = args.takeAt(idx + 1);
        args.removeAt(idx);
        const int eq = raw.indexOf('=');
        if (eq <= 0) {
            std::fprintf(stderr, "--market must look like ETH=49 or SOL=0.52\n");
            return 2;
        }
        double prob = 0.0;
        if (!edge_parse_probability_text(raw.mid(eq + 1), prob)) {
            std::fprintf(stderr, "invalid probability in --market %s\n", qUtf8Printable(raw));
            return 2;
        }
        markets.push_back({raw.left(eq).trimmed().toUpper(), prob});
    }

    int limit = 0;
    if (!limit_raw.isEmpty()) {
        bool ok = false;
        limit = limit_raw.toInt(&ok);
        if (!ok || limit < 1) {
            std::fprintf(stderr, "--limit must be a positive integer\n");
            return 2;
        }
    }

    if (!args.isEmpty()) {
        std::fprintf(stderr, "unknown args: %s\n", qUtf8Printable(args.join(' ')));
        return 2;
    }

    const auto impulse = edge_capture_impulse(QStringLiteral("BTC-USD"),
                                              edge_parse_latency_sources(sources_raw),
                                              duration_ms,
                                              window_seconds,
                                              impulse_options);
    const double btc_prob = services::edge_radar::CryptoImpulseModel::anchor_probability(impulse);
    const QString direction = direction_raw.trimmed().toLower() == QStringLiteral("down")
                                  ? QStringLiteral("down")
                                  : QStringLiteral("up");

    QVector<services::edge_radar::CryptoHourlySignal> rows;
    rows.reserve(markets.size());
    for (const auto& market : markets) {
        rows.push_back(services::edge_radar::CryptoHourlyEdgeModel::score_symbol(
            market.first, market.second, btc_prob, options, direction, 0.0,
            QStringLiteral("%1 live hourly crypto contract").arg(market.first), market.first));
    }
    std::stable_sort(rows.begin(), rows.end(), [](const auto& a, const auto& b) {
        if (a.passes_gate != b.passes_gate)
            return a.passes_gate;
        return a.gate_edge > b.gate_edge;
    });
    while (limit > 0 && rows.size() > limit)
        rows.removeLast();

    return edge_emit_crypto_hourly_live(opts, impulse, rows);
}

static bool edge_parse_double_option(QStringList& args,
                                     const QString& flag,
                                     double& out,
                                     double min_value,
                                     double max_value) {
    QString raw;
    if (!take_string_option(args, flag, raw))
        return false;
    if (raw.isEmpty())
        return true;
    bool ok = false;
    const double parsed = raw.toDouble(&ok);
    if (!ok || parsed < min_value || parsed > max_value) {
        std::fprintf(stderr, "%s must be between %.2f and %.2f\n",
                     qUtf8Printable(flag), min_value, max_value);
        return false;
    }
    out = parsed;
    return true;
}

static bool edge_parse_int_option(QStringList& args,
                                  const QString& flag,
                                  int& out,
                                  int min_value,
                                  int max_value) {
    QString raw;
    if (!take_string_option(args, flag, raw))
        return false;
    if (raw.isEmpty())
        return true;
    bool ok = false;
    const int parsed = raw.toInt(&ok);
    if (!ok || parsed < min_value || parsed > max_value) {
        std::fprintf(stderr, "%s must be between %d and %d\n",
                     qUtf8Printable(flag), min_value, max_value);
        return false;
    }
    out = parsed;
    return true;
}

